css:
.loader {
  color: var(--loader-color, #f97316);
  display: inline-grid;
  padding: 5px;
  background: var(--loader-bg, #ffffff);
  border-radius: 999px;
  filter: blur(4px) contrast(12);
}
.loader:before {
  content: "";
  height: 40px;
  aspect-ratio: 3;
  --c: #0000 64%,currentColor 66% 98%,#0000 101%;
  background:
    radial-gradient(35% 146% at 50% 159%,var(--c)) 0 0,
    radial-gradient(35% 146% at 50% -59%,var(--c)) 100% 100%;
  background-size: calc(200%/3) 50%;
  background-repeat: repeat-x;
  -webkit-mask: repeating-linear-gradient(90deg,currentColor 0 10%,#0000 0 20%);
  animation: l12 .8s infinite linear;
}
@keyframes l12{
  to {background-position: -200% 0,-100% 100%}
}
